SELECT 
FROM protocol_command_outbox
WHERE deleted_at IS NULL
  AND status = #{status}
  AND next_retry_at <= #{now}
ORDER BY next_retry_at ASC, id ASC
LIMIT #{limit}

mapper.update:
UPDATE protocol_command_outbox
SET status = #{lockedStatus},
    locked_by = #{lockedBy},
    locked_at = #{lockedAt},
    updated_at = #{lockedAt}
WHERE deleted_at IS NULL
  AND status = #{pendingStatus}
  AND next_retry_at <= #{lockedAt}
  AND id IN
#{id}

UPDATE protocol_command_outbox
SET status = #{sentStatus},
    sent_at = #{row.sentAt},
    last_error = NULL,
    updated_at = #{row.updatedAt}
WHERE id = #{row.id}
  AND deleted_at IS NULL
  AND status = #{lockedStatus}

UPDATE protocol_command_outbox
SET status = #{deadStatus},
    locked_by = NULL,
    locked_at = NULL,
    last_error = #{row.lastError},
    updated_at = #{row.updatedAt}
WHERE id = #{row.id}
  AND deleted_at IS NULL
  AND status = #{lockedStatus}
